/*
 * Calculates temperature thresholds array (one element for each Calcification Level) using linear interpolation between the values in setting file.
 *
 * @param input_current = value of heater current used as input for the interpolation
 * @param interpolated_thresholds = pointer to the array of interpolated thresholds

 */
static void TemperatureThresholdsInterpolation(uint16 input_current, uint16 *interpolated_thresholds)
{
	uint8 heater_current_index;
	uint8 level_index;

	heater_current_index = 0;

	while ((heater_current_index < HEATER_CURRENT_THRESHOLDS_NUM) && (input_current > ENDIANU16_STON(SF_HCD_Parameters->Heater_Current_i[heater_current_index])))
	{
		heater_current_index ++;
	}

	if (heater_current_index == (uint8)0)
	{
		// Special case: input_current <= SF_HCD_Parameters->Heater_Current_i[0]
		heater_current_index = 1;
		input_current = ENDIANU16_STON(SF_HCD_Parameters->Heater_Current_i[0]);
	}
	else if (heater_current_index == HEATER_CURRENT_THRESHOLDS_NUM)
	{
		// Special case: input_current > SF_HCD_Parameters->Heater_Current_i[5]
		heater_current_index = 5;
		input_current = ENDIANU16_STON(SF_HCD_Parameters->Heater_Current_i[5]);
	}
	else
	{
		// Do nothing
	}

	for (level_index = 0; level_index < SF_Calcification_Levels_Number; level_index ++)
	{
		const HEATER_CALCIFICATION_LEVEL_DIP_PARAMS_TYPE *current_level_params_ptr = SF_HCD_Lvl_Parameters + level_index;;
		uint16 temp_thresh_min = ENDIANU16_STON(current_level_params_ptr->Temperature_for_Heater_Power[heater_current_index - (uint8)1]);
		uint16 temp_thresh_max = ENDIANU16_STON(current_level_params_ptr->Temperature_for_Heater_Power[heater_current_index]);
		uint16 current_thres_min = ENDIANU16_STON(SF_HCD_Parameters->Heater_Current_i[heater_current_index - (uint8)1]);
		uint16 current_thres_max = ENDIANU16_STON(SF_HCD_Parameters->Heater_Current_i[heater_current_index]);

		if ((current_thres_max - current_thres_min) != (uint16)0)
		{
			*(interpolated_thresholds + level_index) = (uint16)(temp_thresh_min + (((temp_thresh_max - temp_thresh_min) * (input_current - current_thres_min)) /(current_thres_max - current_thres_min)));
		}
		else
		{
			*(interpolated_thresholds + level_index) = temp_thresh_min;
		}
	}
}


/*
 * Update the pointer to the set of parameters correspondent to the current HCD_Calcification_Level
 * If HCD_Counters.Alarm_Counter, HCD_Counters.Reduction_Counter or HCD_Counters.Lockout_Counter exceeds their respective
 * thresholds, the counters are aligned to the threshold' value. It implies resetting the counter if threshold equals 0.
 *
 * @param current_level_params_ptr = pointer to the set of parameters correspondent to the current HCD_Calcification_Level

 */
static void UpdateParamsPointerAndAlignCountersToThresholds(const HEATER_CALCIFICATION_LEVEL_DIP_PARAMS_TYPE **current_level_params_ptr)
{
    // Update pointer to the set of parameters correspondent to the current HCD_Calcification_Level
   *current_level_params_ptr = SF_HCD_Lvl_Parameters + HCD_Calcification_Level;

    if (HCD_Counters.Alarm_Counter > (*current_level_params_ptr)->Descale_Alarm_Threshold)
	{
		HCD_Counters.Alarm_Counter = (*current_level_params_ptr)->Descale_Alarm_Threshold;
	}

	if (HCD_Counters.Reduction_Counter > (*current_level_params_ptr)->Calcification_Reduction_Threshold)
	{
		HCD_Counters.Reduction_Counter = (*current_level_params_ptr)->Calcification_Reduction_Threshold;
	}

	if (HCD_Counters.Lockout_Counter > (*current_level_params_ptr)->Lockout_Threshold)
	{
		HCD_Counters.Lockout_Counter = (*current_level_params_ptr)->Lockout_Threshold;
	}
}
